1	%% NR Cell Performance вЂ” 128T128R Downlink MU-MIMO (Rel-19 eTypeII)
2	% Evaluates DL MU-MIMO system performance using abstract PHY (L2SM),
3	% 128-antenna gNB with eTypeII-r19 codebook (TS 38.214 В§5.2.2.2.5a).
4	%
5	% Author: ThangTQ23 вЂ” VSI, 2026-04
6	
7	%% 1. Simulation Setup
8	
9	% Prepend local patched wirelessnetwork + 5g toolbox overrides so that
10	% 128T-capable nrGNB (allows NumTransmitAntennas up to 128) and the
11	% eTypeII-r19 PHY stack are found before the installed support packages.
12	projectRoot = fileparts(mfilename('fullpath'));
13	addpath(genpath(fullfile(projectRoot, 'wirelessnetwork')), '-begin');
14	addpath(genpath(fullfile(projectRoot, '5g')),              '-begin');
15	
16	wirelessnetworkSupportPackageCheck
17	
18	% в”Ђв”Ђ PMI / CQI reporting mode for 128T eTypeII-r19 в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
19	% 'Wideband' : single precoder + single CQI across full BW.
20	%              Fastest simulation; suitable for quick sweeps or low-spec PCs.
21	% 'Subband'  : per-subband precoder (PMI) + per-subband CQI (Phase 4b).
22	%              Each subband = 4 RBs (TS 38.214 Table 5.2.1.4-2, NRBв€€[24,72]).
23	%              Best frequency-selective accuracy; ~6Г— slower LQM compute.
24	pmiCQIMode = "Subband";   % <-- change to "Wideband" for faster runs
25	
26	rng("default")
27	numFrameSimulation = 50;
28	networkSimulator   = wirelessNetworkSimulator.init;
29	
30	%% 2. gNB Configuration
31	% 128T128R massive MIMO, TDD, 4.9 GHz n79, 10 MHz / 30 kHz SCS
32	% (Use channelBW = 100e6 for production; 10 MHz here for fast simulation.)
33	
34	gNBPosition  = [0 0 30];       % [x y z] metres
35	duplexType   = "TDD";
36	numUEs       = 64;             % total UEs вЂ” defined here so SRSPeriodicityUE can auto-scale
37	
38	carrierFreq  = 4.9e9;          % n79 band centre frequency (Hz)
39	channelBW    = 10e6;           % channel bandwidth (Hz)
40	scs          = 30e3;           % subcarrier spacing (Hz)
41	
42	% Valid NRB per 3GPP TS 38.104 Table 5.3.2-1 for FR1 30 kHz SCS:
43	%   5 MHzв†’11, 10 MHzв†’24, 15 MHzв†’38, 20 MHzв†’51, 40 MHzв†’106, 100 MHzв†’273
44	numRB = 24;   % matches channelBW = 10 MHz, SCS = 30 kHz
45	
46	gNB = nrGNB( ...
47	    Position             = gNBPosition, ...
48	    TransmitPower        = 60, ...
49	    CarrierFrequency     = carrierFreq, ...
50	    ChannelBandwidth     = channelBW, ...
51	    SubcarrierSpacing    = scs, ...
52	    NumResourceBlocks    = numRB, ...
53	    NumTransmitAntennas  = 128, ...
54	    NumReceiveAntennas   = 128, ...
55	    DuplexMode           = duplexType, ...
56	    ReceiveGain          = 11, ...
57	    SRSPeriodicityUE     = 20);
58	
59	disp("gNB: " + duplexType + ", " + carrierFreq/1e9 + " GHz, " + ...
60	     channelBW/1e6 + " MHz, NRB=" + numRB + ", 128T128R");
61	
62	%% 3. Scheduler Configuration
63	% CSI measurement source: "CSI-RS" (eTypeII-r19 feedback) or "SRS" (TDD reciprocity)
64	
65	csiMeasurementSignalDLType = "CSI-RS";
66	allocationType             = 0;   % RAT-0 (RBG-based)
67	
68	% CSI-RS mode fields: SemiOrthogonalityFactor, MinCQI (not MinSINR вЂ” that is SRS-only)
69	muMIMOConfiguration = struct( ...
70	    MaxNumUsersPaired       = 12, ...
71	    MaxNumLayers            = 24, ...
72	    MinNumRBs               = 2, ...
73	    SemiOrthogonalityFactor = 0.5, ...
74	    MinCQI                  = 1);
75	
76	% OLLA: TargetBLER = StepDown/(StepDown+StepUp) = 0.03/0.30 = 10%
77	% Resets to InitialOffset=0 on each CSI report (by design, fresh CQI window).
78	% Without this, LinkAdaptationConfigDL=[] в†’ OLLA disabled в†’ BLER ~60%.
79	oLLAConfig = struct('InitialOffset', 0, 'StepUp', 0.27, 'StepDown', 0.03);
80	
81	configureScheduler(gNB, ...
82	    ResourceAllocationType  = allocationType, ...
83	    MaxNumUsersPerTTI       = 32, ...
84	    MUMIMOConfigDL          = muMIMOConfiguration, ...
85	    CSIMeasurementSignalDL  = csiMeasurementSignalDLType, ...
86	    LinkAdaptationConfigDL  = oLLAConfig);
87	
88	%% 4. UE Deployment
89	% UEs scattered across a 120В° sector, min 50 m вЂ“ max 500 m from gNB.
90	% Distance drawn from uniform distribution on area (pdf в€ќ r) via sqrt-trick
91	% so that UEs are spread evenly over the sector area, not clustered near gNB.
92	
93	ueRxGain       = 0;
94	ueNumTxAnt     = 4;
95	ueNumRxAnt     = 4;
96	
97	rMin = 50;   rMax = 500;   % metres
98	azDeg  = -60 + 120 .* rand(numUEs, 1);                      % uniform azimuth in [-60В°, +60В°]
99	rDist  = sqrt(rMin^2 + (rMax^2 - rMin^2) .* rand(numUEs, 1)); % uniform on area (pdf в€ќ r)
100	[xPos, yPos, zPos] = sph2cart(deg2rad(azDeg), zeros(numUEs,1), rDist);
101	uePositions = [xPos, yPos, zPos] + gNBPosition;
102	ueNames     = "UE-" + (1:numUEs);
103	
104	UEs = nrUE( ...
105	    Name                = ueNames, ...
106	    Position            = uePositions, ...
107	    ReceiveGain         = ueRxGain, ...
108	    NumTransmitAntennas = ueNumTxAnt, ...
109	    NumReceiveAntennas  = ueNumRxAnt);
110	
111	% Apply PMI/CQI mode before connectUE so nrNodeValidation picks it up.
112	gNB.PMICQIMode = pmiCQIMode;
113	
114	connectUE(gNB, UEs, FullBufferTraffic = "DL", CSIReportPeriodicity = 10);
115	
116	%% 5. Network Simulator вЂ” Add Nodes
117	
118	addNodes(networkSimulator, gNB);
119	addNodes(networkSimulator, UEs);
120	
121	%% 6. CDL Channel Model
122	% CDL-B, 100 ns delay spread, 5 Hz Doppler (frequency-selective, rank-friendly)
123	
124	channelConfig = struct( ...
125	    DelayProfile        = "CDL-B", ...
126	    DelaySpread         = 100e-9, ...
127	    MaximumDopplerShift = 5);
128	
129	channels = hNRCreateCDLChannels(channelConfig, gNB, UEs);
130	customChannelModel = hNRCustomChannelModel(channels);
131	addChannelModel(networkSimulator, @customChannelModel.applyChannelModel);
132	
133	%% 7. Logging and Visualization
134	
135	enableTraces = true;
136	
137	if enableTraces
138	    simSchedulingLogger = helperNRSchedulingLogger(numFrameSimulation, gNB, UEs);
139	    simPhyLogger        = helperNRPhyLogger(numFrameSimulation, gNB, UEs);
140	end
141	
142	numMetricPlotUpdates = 200;
143	metricsVisualizer = helperNRMetricsVisualizer(gNB, UEs, ...
144	    RefreshRate         = numMetricPlotUpdates, ...
145	    PlotSchedulerMetrics = true, ...
146	    PlotPhyMetrics      = false, ...
147	    PlotCDFMetrics      = true, ...
148	    LinkDirection       = 0);
149	
150	simulationLogFile = "simulationLogs";
151	
152	%% 8. Simulation Conditions Summary
153	
154	slotsPerSubfm  = scs / 15e3;           % slots per subframe (2 for 30 kHz SCS)
155	slotDurMs      = 1 / slotsPerSubfm;    % ms per slot
156	slotsPerFrm    = 10 * slotsPerSubfm;   % slots per 10-ms frame
157	csiPeriodicity = 10;                   % slots (set in connectUE call above)
158	csiPeriodMs    = csiPeriodicity * slotDurMs;
159	numCSIEvents   = floor(numFrameSimulation * slotsPerFrm / csiPeriodicity);
160	
161	if strcmpi(pmiCQIMode, 'Subband')
162	    if numRB >= 145; sbSize = 16; elseif numRB >= 73; sbSize = 8; else; sbSize = 4; end
163	    numSubbands = ceil(numRB / sbSize);
164	    oh_cqi = 4 + 2*(numSubbands - 1);   % wideband base + differential per extra subband
165	    modeStr = sprintf('Subband (PMI+CQI) | %d Г— %d RBs', numSubbands, sbSize);
166	else
167	    sbSize = numRB;  numSubbands = 1;  oh_cqi = 4;
168	    modeStr = 'Wideband (PMI+CQI)';
169	end
170	oh_ri = 2;  oh_pmi = 20;   % RI: ceil(log2(4)); PMI approx (eTypeII-r19, L=2)
171	oh_total = oh_ri + oh_cqi + oh_pmi;
172	
173	sep = repmat('в•ђ', 1, 67);
174	fprintf('\n%s\n', sep);
175	fprintf('  SIMULATION CONDITIONS вЂ” 128T128R MU-MIMO DL, Rel-19 eTypeII\n');
176	fprintf('%s\n', sep);
177	fprintf('  System\n');
178	fprintf('    gNB  : %dT/%dR | %.1f GHz (n79) | %s | %d dBm Tx\n', ...
179	    gNB.NumTransmitAntennas, gNB.NumReceiveAntennas, ...
180	    carrierFreq/1e9, duplexType, 34);
181	fprintf('           BW=%.0f MHz | NRB=%d | SCS=%.0f kHz | Rx Gain=11 dB\n', ...
182	    channelBW/1e6, numRB, scs/1e3);
183	fprintf('    UE   : %d nodes | %dTx/%dRx | R=500 m | Az=[-60В°,+60В°] | Rx Gain=0 dB\n', ...
184	    numUEs, ueNumTxAnt, ueNumRxAnt);
185	fprintf('  Channel  : %s | RMS delay=%.0f ns | f_D=%.0f Hz\n', ...
186	    channelConfig.DelayProfile, channelConfig.DelaySpread*1e9, channelConfig.MaximumDopplerShift);
187	fprintf('  Scheduler\n');
188	fprintf('    Source : %s | MU-MIMO в‰¤%d paired / в‰¤%d layers | RAT-%d\n', ...
189	    csiMeasurementSignalDLType, muMIMOConfiguration.MaxNumUsersPaired, ...
190	    muMIMOConfiguration.MaxNumLayers, allocationType);
191	fprintf('             MinCQI=%d | Semiortho=%.1f | SRS period=20 ms\n', ...
192	    muMIMOConfiguration.MinCQI, muMIMOConfiguration.SemiOrthogonalityFactor);
193	fprintf('  CSI Feedback\n');
194	fprintf('    Signal   : CSI-RS (4Г—32-port Row-18 resources в‰Ў 128T)\n');
195	fprintf('    Codebook : eTypeII-r19 | Panel [1Г—16Г—4] | L=2 beams | PC=1\n');
196	fprintf('    Mode     : %s\n', modeStr);
197	fprintf('    Period   : %d slots (%.1f ms) в†’ ~%d reports/UE in %d frames\n', ...
198	    csiPeriodicity, csiPeriodMs, numCSIEvents, numFrameSimulation);
199	fprintf('    OH est.  : RI=%d + CQI=%d + PMIв‰€%d в‰€ %d bits/report\n', ...
200	    oh_ri, oh_cqi, oh_pmi, oh_total);
201	fprintf('    [Live CSI events printed below for UE-1 and UE-2 only]\n');
202	fprintf('  Simulation : %d frames | %.0f ms | full-buffer DL | logging=%s\n', ...
203	    numFrameSimulation, numFrameSimulation*10, upper(char(string(enableTraces))));
204	fprintf('%s\n\n', sep);
205	
206	%% 9. Run Simulation
207	
208	simulationTime = numFrameSimulation * 1e-2;   % seconds
209	run(networkSimulator, simulationTime);
210	
211	%% 10. Results вЂ” KPI Summary
212	% Display cell throughput, spectral efficiency, and BLER ECDF.
213	
214	displayPerformanceIndicators(metricsVisualizer);
215	
216	%% 11. Save Traces
217	
218	if enableTraces
219	    simulationLogs = cell(1,1);
220	    if gNB.DuplexMode == "FDD"
221	        logInfo = struct(DLTimeStepLogs=[], ULTimeStepLogs=[], ...
222	                         SchedulingAssignmentLogs=[], PhyReceptionLogs=[]);
223	        [logInfo.DLTimeStepLogs, logInfo.ULTimeStepLogs] = ...
224	            getSchedulingLogs(simSchedulingLogger);
225	    else  % TDD
226	        logInfo = struct(TimeStepLogs=[], SchedulingAssignmentLogs=[], ...
227	                         PhyReceptionLogs=[]);
228	        logInfo.TimeStepLogs = getSchedulingLogs(simSchedulingLogger);
229	    end
230	    logInfo.SchedulingAssignmentLogs = getGrantLogs(simSchedulingLogger);
231	    logInfo.PhyReceptionLogs         = getReceptionLogs(simPhyLogger);
232	    simulationLogs{1} = logInfo;
233	    save(simulationLogFile, "simulationLogs");
234	end
235	
236	%% 11b. Grant / MCS Summary вЂ” gNB Downlink Decisions
237	
238	if enableTraces
239	    colMap   = simSchedulingLogger.GrantLogsColumnIndexMap;
240	    % getGrantLogs prepends an alphabetical header row; skip it, use colMap for column indices.
241	    grantRaw = logInfo.SchedulingAssignmentLogs(2:end, :);
242	
243	    rntiCol  = colMap('RNTI');
244	    mcsCol   = colMap('MCS Index');
245	    lyrCol   = colMap('NumLayers');
246	    typeCol  = colMap('Grant Type');
247	
248	    isDL   = strcmp(grantRaw(:, typeCol), 'DL');
249	    dlData = grantRaw(isDL, :);
250	    nDL    = sum(isDL);
251	
252	    sep2 = repmat('в”Ђ', 1, 67);
253	    fprintf('\n%s\n', sep2);
254	    fprintf('  gNB DL Grant Summary  (%d grants | %d frames | %s mode)\n', ...
255	        nDL, numFrameSimulation, pmiCQIMode);
256	    fprintf('%s\n', sep2);
257	    fprintf('  %-6s  %7s  %8s  %8s  %8s  %8s\n', ...
258	        'UE', 'Grants', 'MCS avg', 'MCS min', 'MCS max', 'Lyr avg');
259	    fprintf('%s\n', sep2);
260	    for ueIdx = 1:numUEs
261	        mask = cell2mat(dlData(:, rntiCol)) == ueIdx;
262	        if ~any(mask); continue; end
263	        mcsV = cell2mat(dlData(mask, mcsCol));
264	        lyrV = cell2mat(dlData(mask, lyrCol));
265	        fprintf('  UE-%-3d  %7d  %8.1f  %8d  %8d  %8.1f\n', ...
266	            ueIdx, sum(mask), mean(mcsV), min(mcsV), max(mcsV), mean(lyrV));
267	    end
268	    fprintf('%s\n\n', sep2);
269	end
270	
271	%% 12. MU-MIMO Pairing Analysis вЂ” UEs per RB Distribution
272	% Histogram shows how often multiple UEs share the same RB in DL slots.
273	
274	if enableTraces
275	    avgNumUEsPerRB = calculateAvgUEsPerRBDL(logInfo, gNB.NumResourceBlocks, ...
276	                                             allocationType, duplexType);
277	    figure;
278	    histogram(avgNumUEsPerRB, BinWidth=0.1);
279	    title("Distribution of Average Number of UEs per RB in DL Slots");
280	    xlabel("Average Number of UEs per RB");
281	    ylabel("Number of Occurrences");
282	    grid on;
283	end
284	
285	%% Local Function
286	
287	function avgUEsPerRB = calculateAvgUEsPerRBDL(logInfo, numResourceBlocks, ratType, duplexMode)
288	    % Returns average number of UE nodes per RB for each DL slot.
289	    % Supports RAT-0 (RBG-based) and RAT-1 (contiguous-RB-based) allocation.
290	
291	    if strcmp(duplexMode, 'TDD')
292	        timeStepLogs    = logInfo.TimeStepLogs;
293	        freqAllocations = timeStepLogs(:, 5);
294	    else
295	        timeStepLogs    = logInfo.DLTimeStepLogs;
296	        freqAllocations = timeStepLogs(:, 4);
297	    end
298	
299	    numOfSlots = size(timeStepLogs, 1) - 1;
300	
301	    if ~ratType
302	        % Derive per-RBG sizes per TS 38.214
303	        numRBG       = size(freqAllocations{2}, 2);
304	        P            = ceil(numResourceBlocks / numRBG);
305	        numRBsPerRBG = P * ones(1, numRBG);
306	        remainder    = mod(numResourceBlocks, P);
307	        if remainder > 0
308	            numRBsPerRBG(end) = remainder;
309	        end
310	    end
311	
312	    avgUEsPerRB = zeros(1, numOfSlots);
313	
314	    for slotIdx = 1:numOfSlots
315	        % Skip UL slots in TDD
316	        if strcmp(duplexMode, 'TDD') && ~strcmp(timeStepLogs{slotIdx+1, 4}, 'DL')
317	            continue;
318	        end
319	
320	        freqAllocation = freqAllocations{slotIdx + 1};
321	
322	        if ~ratType
323	            % RAT-0: weight each RBG by its RB count
324	            totalUniqueUEs = sum(arrayfun( ...
325	                @(i) nnz(freqAllocation(:,i) > 0) * numRBsPerRBG(i), ...
326	                1:length(numRBsPerRBG)));
327	            avgUEsPerRB(slotIdx) = totalUniqueUEs / numResourceBlocks;
328	        else
329	            % RAT-1: count UEs per contiguous RB allocation
330	            ueRBUsage = zeros(1, numResourceBlocks);
331	            for ueIdx = 1:size(freqAllocation, 1)
332	                startRB = freqAllocation(ueIdx, 1);
333	                numRBs  = freqAllocation(ueIdx, 2);
334	                ueRBUsage(startRB+1 : startRB+numRBs) = ...
335	                    ueRBUsage(startRB+1 : startRB+numRBs) + 1;
336	            end
337	            avgUEsPerRB(slotIdx) = mean(ueRBUsage(ueRBUsage > 0));
338	        end
339	    end
340	
341	    % Remove zero entries (UL slots)
342	    avgUEsPerRB = avgUEsPerRB(avgUEsPerRB > 0);
343	end
344

