                    for k=1:numEligibleUEs
                        schedulerInput.cqiRBG(k,:) = schedulerInput.channelQuality(k, startRBIndex+1 : lastRBIndex+1);
                        cqiSetRBG = floor(sum(schedulerInput.cqiRBG, 2)/size(schedulerInput.cqiRBG, 2));
