289	function avgUEsPerRB = calculateAvgUEsPerRBDL(logInfo, numResourceBlocks, ratType, duplexMode)
290	    % Returns average number of UE nodes per RB for each DL slot.
291	    % Supports RAT-0 (RBG-based) and RAT-1 (contiguous-RB-based) allocation.
292	
293	    if strcmp(duplexMode, 'TDD')
294	        timeStepLogs    = logInfo.TimeStepLogs;
295	        freqAllocations = timeStepLogs(:, 5);
296	    else
297	        timeStepLogs    = logInfo.DLTimeStepLogs;
298	        freqAllocations = timeStepLogs(:, 4);
299	    end
300	
301	    numOfSlots = size(timeStepLogs, 1) - 1;
302	
303	    if ~ratType
304	        % Derive per-RBG sizes per TS 38.214
305	        numRBG       = size(freqAllocations{2}, 2);
306	        P            = ceil(numResourceBlocks / numRBG);
307	        numRBsPerRBG = P * ones(1, numRBG);
308	        remainder    = mod(numResourceBlocks, P);
309	        if remainder > 0
310	            numRBsPerRBG(end) = remainder;
311	        end
312	    end
313	
