264	            %validateConnectionConfig Validate per UE connection information
265	
266	            % ThangTQ23_128T128R_Rel19: detect 128T antenna configuration
267	            % (4Г—32-port Row-18 CSI-RS resources в†’ 128 total ports).
268	            % For 128T, always use eTypeII-r19 regardless of CSIReportType (1 or 2).
269	            is128T = ~isempty(connConfig.CSIRSConfiguration) && ...
270	                     numel(connConfig.CSIRSConfiguration) >= 4 && ...
271	                     sum([connConfig.CSIRSConfiguration.NumCSIRSPorts]) >= 128;
272	
273	            if is128T
274	                % в”Ђв”Ђ Rel-19 eTypeII (TS 38.214 В§5.2.2.2.5a) for 128-port massive MIMO в”Ђв”Ђ
275	                % Supports MU-MIMO, subband PMI, rank up to 4.
276	                csiReportConfig.CodebookType               = 'eTypeII-r19';
277	                csiReportConfig.PanelDimensions            = [1 16 4]; % N1=16, N2=4 в†’ 128 ports
278	                csiReportConfig.NumberOfBeams              = 2;        % L=2 (ParameterCombination=1)
279	                csiReportConfig.ParameterCombination       = 1;
280	                csiReportConfig.SubbandAmplitude           = false;    % wideband amplitude
281	                csiReportConfig.NumberOfPMISubbandsPerCQISubband = 1;
282	                csiReportConfig.RIRestriction              = [1 1 1 1]; % rank 1вЂ“4
283	            elseif connConfig.CSIReportType == 1
284	                % Applicable for CSI type-I report
285	                csiReportConfig.CodebookType = 'Type1SinglePanel';
286	                % Restricting maximum rank to 4 as only single codeword is supported
287	                csiReportConfig.RIRestriction = [1 1 1 1 0 0 0 0];
288	            else
289	                % Applicable for CSI type-II report
290	                csiReportConfig.CodebookType = 'Type2';
291	                % ThangTQ23_128T128R_Rel19: CSIRSConfiguration may be an array вЂ”
292	                % use first element for scalar property access.
293	                csirs1_type2 = connConfig.CSIRSConfiguration(1);
294	                % Added clause as mentioned in 3GPP TS 38.214 5.2.2.2.3
295	                if (csirs1_type2.NumCSIRSPorts == 4)
296	                    csiReportConfig.NumberOfBeams = 2;
297	                else
298	                    % For NumCSIRSPorts > 4, NumberOfBeams(L) can be either {2, 3, 4}.
299	                    % Selecting L = 4.
300	                    csiReportConfig.NumberOfBeams = 4;
301	                end
302	                csiReportConfig.SubbandAmplitude = false;
303	                csiReportConfig.PhaseAlphabetSize = 4;
304	            end
305	
306	            if ~isempty(connConfig.CSIRSConfiguration)
307	                % Set CSI-RS configuration on the full bandwidth
308	                csiReportConfig.NStartBWP = 0;
309	                csiReportConfig.NSizeBWP = connConfig.NumResourceBlocks;
310	                % ThangTQ23_128T128R_Rel19 Phase 4/4b: PMI/CQI mode for 128T.
311	                % connConfig.PMICQIMode is injected by nrGNB.connectUE from
312	                % gNB.PMICQIMode (set in the main script via pmiCQIMode flag).
313	                %   'Subband'  в†’ per-subband PMI + per-subband CQI (Phase 4b)
314	                %   'Wideband' в†’ single PMI + single CQI (fast baseline)
315	                use128TSubband = is128T && isfield(connConfig,'PMICQIMode') && ...
316	                                 strcmpi(connConfig.PMICQIMode, 'Subband');
317	                if use128TSubband
318	                    csiReportConfig.CQIMode = 'Subband';  % per-subband CQI
319	                    csiReportConfig.PMIMode = 'Subband';  % per-subband precoder W
320	                    csiReportConfig.PRGSize = 4;           % PRG = PMI subband = 4 RBs (TS 38.214 Table 5.2.1.4-2, NRBв€€[24,72])
321	                    % SubbandSize required by nrRISelect public validation when PMIMode='Subband'.
322	                    nrb = connConfig.NumResourceBlocks;
323	                    if nrb >= 145
324	                        csiReportConfig.SubbandSize = 16;
325	                    elseif nrb >= 73
326	                        csiReportConfig.SubbandSize = 8;
327	                    else
328	                        csiReportConfig.SubbandSize = 4;  % NRBв€€[24,72]
329	                    end
330	                else
331	                    csiReportConfig.CQIMode = 'Wideband';
332	                    csiReportConfig.PMIMode = 'Wideband';
333	                    csiReportConfig.PRGSize = [];
334	                end
