336	                csiReportConfig.CodebookSubsetRestriction = [];
337	                csiReportConfig.i2Restriction = [];
338	                if ~isfield(csiReportConfig,'RIRestriction')
339	                    csiReportConfig.RIRestriction = [];
340	                end
341	                % ThangTQ23_128T128R_Rel19: CSIRSConfiguration may be an array (4 resources for 128T).
342	                % Use first element for scalar property access.
343	                csirs1 = connConfig.CSIRSConfiguration(1);
344	                if ~is128T && csirs1.NumCSIRSPorts > 2
345	                    % Supported panel configurations for type 1 single
346	                    % panel codebooks, as defined in TS 38.214 Table
347	                    % 5.2.2.2.1-2. Each row contains: number of CSI-RS
348	                    % ports, N1, N2. Read N1, N2 from the row with
