351	                        16 8 1; 24 4 3; 24 6 2; 24 12 1; 32 4 4; 32 8 2; 32 16 1];
352	                    configIdx = find(panelConfigs(:,1) == csirs1.NumCSIRSPorts);
353	                    if ~isempty(configIdx)
