362	                if strcmp(connConfig.DuplexMode, "FDD")
363	                    if isempty(connConfig.CSIReportPeriodicity)
364	                        % Automatic report periodicity and offset calculation in slots
365	                        connConfig.CSIReportPeriod = [csirsTxPeriod(1) mod(csirsTxPeriod(2) + reportSlotOffSet, csirsTxPeriod(1))];
366	                    else
